class Solution {
    public int compress(char[] chars) {
        if (chars.length == 0) {
            return 0;
        }
        int i = 0;
        int j = 1;
        while (j < chars.length) {
            if (chars[i] == chars[j]) {
                j++;
            } else {
                if (j - i > 1) {
                    chars[i + 1] = (char) (j - i + '0');
                }
                i = j;
                j++;
            }
        }
        if (j - i > 1) {
            chars[i + 1] = (char) (j - i + '0');
        }
        return i + 1;
    }
}
